framework_css:
:root {
  /* Color system */
  --color-primary: #ff1684; /* bright pink brand */
  --color-primary-soft: #f5f5f5; /* soft light background */

  --color-secondary-yellow: #f2c94c;
  --color-secondary-orange: #f2994a;

  --color-neutral-0: #ffffff;
  --color-neutral-100: #f5f5f5;
  --color-neutral-200: #e0e0e0;
  --color-neutral-500: #777777;
  --color-neutral-800: #333333;

  --color-success: #27ae60;
  --color-error: #eb5757;
  --color-warning: #f2c94c;
  --color-info: #2d9cdb;

  /* Header gradient (from screenshot) */
  --color-header-top: #f7f7f7;
  --color-header-bottom: #a3a3a3;

  /* Typography */
  --font-heading: 'Fredoka', 'Helvetica', sans-serif;
  --font-body: 'Nunito', 'Arial', sans-serif;

  --font-size-h1: 36px;
  --font-size-h2: 28px;
  --font-size-h3: 22px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --container-max-width: 1120px;

  /* Misc */
  --radius-sm: 4px;
  --radius-md: 6px;
  --shadow-soft: 0 2px 8px rgba(0, 0, 0, 0.06);
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-800);
  background-color: var(--color-neutral-0);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover {
  text-decoration: none;
}

a:focus-visible {
  outline: 2px solid var(--color-primary);
  outline-offset: 2px;
}

.site-wrapper {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.container {
  width: 100%;
  max-width: var(--container-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-3);
  padding-right: var(--space-3);
}

/* ==========================
   Header & Primary Navigation
   ========================== */

.site-header {
  background: linear-gradient(180deg, var(--color-header-top) 0%, var(--color-header-bottom) 100%);
  color: var(--color-neutral-0);
  padding-top: var(--space-3);
  padding-bottom: var(--space-6);
}

.header-inner {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
}

/* Brand / Logo */

.brand-link {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  text-decoration: none;
}

.brand-logo {
  width: 72px;
  height: auto;
}

.brand-text {
  display: flex;
  flex-direction: column;
  color: var(--color-neutral-0);
}

.brand-title {
  font-family: var(--font-heading);
  font-size: 26px;
  font-weight: var(--font-weight-semibold);
  line-height: var(--line-height-tight);
}

.brand-subtitle {
  font-family: var(--font-body);
  font-size: 13px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  opacity: 0.85;
}

/* Navigation */

.main-nav {
  margin-top: var(--space-1);
}

.nav-list {
  list-style: none;
  display: flex;
  align-items: center;
  gap: var(--space-3);
  margin: 0;
  padding: 0;
}

.nav-item a {
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--color-neutral-0);
  padding-bottom: 4px;
  transition: color 0.18s ease;
}

.nav-item a:hover {
  color: var(--color-primary);
}

.nav-item--active a,
.nav-item a[aria-current='page'] {
  color: var(--color-primary);
}

/* ==========================
   Main Content Shell
   ========================== */

.site-main {
  flex: 1 0 auto;
  background-color: var(--color-neutral-0);
  padding-top: var(--space-5);
  padding-bottom: var(--space-6);
}

/* The content area is intentionally minimal here. 
   Page templates can define their own layout inside .site-main .container. */

/* ==========================
   Footer
   ========================== */

.site-footer {
  margin-top: auto;
  background-color: var(--color-neutral-100);
  color: var(--color-neutral-500);
  border-top: 1px solid var(--color-neutral-200);
}

.footer-inner {
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  padding-top: var(--space-5);
  padding-bottom: var(--space-4);
}

.footer-brand-name {
  font-family: var(--font-heading);
  font-size: 22px;
  font-weight: var(--font-weight-semibold);
  color: var(--color-neutral-800);
}

.footer-tagline {
  margin: var(--space-1) 0 0;
  max-width: 360px;
  font-size: var(--font-size-small);
  line-height: var(--line-height-relaxed);
}

.footer-links-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: var(--space-4);
}

.footer-heading {
  margin: 0 0 var(--space-2);
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--color-neutral-800);
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-links li + li {
  margin-top: var(--space-1);
}

.footer-links a {
  font-size: var(--font-size-small);
  color: var(--color-neutral-500);
  transition: color 0.18s ease;
}

.footer-links a:hover {
  color: var(--color-primary);
}

.footer-bottom {
  border-top: 1px solid var(--color-neutral-200);
  background-color: var(--color-neutral-100);
}

.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: center;
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
}

.footer-copy {
  margin: 0;
  font-size: var(--font-size-small);
  color: var(--color-neutral-500);
}

/* ==========================
   Responsive Adjustments
   ========================== */

@media (max-width: 900px) {
  .header-inner {
    flex-direction: column;
    align-items: flex-start;
  }

  .main-nav {
    margin-top: var(--space-3);
    width: 100%;
  }

  .nav-list {
    flex-wrap: wrap;
    row-gap: var(--space-1);
    column-gap: var(--space-3);
  }

  .footer-links-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 600px) {
  .site-header {
    padding-bottom: var(--space-5);
  }

  .brand-logo {
    width: 60px;
  }

  .brand-title {
    font-size: 22px;
  }

  .container {
    padding-left: var(--space-2);
    padding-right: var(--space-2);
  }
}
